// generar_240_paseo_tiempo_exacto.js
// CHIQUI Entre Señales — Tiempo exacto de paseo
//
// IMPORTANTE: primero corre sql_240_paseo_minutos_exactos.sql en
// Supabase (New snippet) — crea la columna paseo_minutos_exactos en
// registros_diarios.
//
// Qué hace:
// 1) app/registro-diario/page.tsx → agrega una 6ta opción en Paseo,
//    "⏱️ Registrar tiempo exacto", al lado de los 5 rangos actuales
//    (que se conservan porque son rápidos de tocar). Al seleccionarla,
//    aparece bajo el grid un mini panel "¿Cuánto duró el paseo?" con
//    dos selects (horas 0-12, minutos en pasos de 5) que muestra el
//    total en vivo (ej. "= 79 min"). Al cambiar a otra opción o
//    deseleccionar, el valor exacto se limpia solo. Se guarda en la
//    nueva columna paseo_minutos_exactos.
// 2) app/analisis/page.tsx → el promedio mensual, el gráfico de los
//    últimos 7 días y la racha ahora usan el minuto EXACTO cuando el
//    usuario lo capturó (más preciso), y caen al promedio del rango
//    cuando el usuario eligió uno de los botones rápidos. Sin cambio
//    para nadie que prefiera los rangos.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_240_paseo_tiempo_exacto.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/registro-diario/page.tsx",
    base64: ""
  },
  {
    ruta: "app/analisis/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 2 archivos escritos. Recuerda: SQL primero, luego git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
